{
        struct obd_device       *obd = mdt2obd_dev(m);
        ...
        lustre_cfg_bufs_reset(bufs, obd->obd_name); //can be replaced
        ...
}

In mdt_adapt_sptlrpc_conf()
{
        struct mdt_device       *m = mdt_dev(obd->obd_lu_dev);
        ....
        if (rc) {
                CERROR("mdt %s: failed get sptlrpc rules: %d\n",
                       obd->obd_name, rc);//can be replaced
                return rc;
        }
        ...
}

And in mdt_fid2path() and others.

Please have a full check if you want to replace them all.
